#!/usr/bin/env python3
"""
    ╔═══════════════════════════════════════════════════════════════╗
    ║                                                               ║
    ║          A N D U R I L   T R A D I N G   S U I T E           ║
    ║                                                               ║
    ║             "Flame of the West  --  Reforged"                 ║
    ║                                                               ║
    ╚═══════════════════════════════════════════════════════════════╝

    Anduril v1.0  --  Cross-platform installer
    Supports: macOS (Apple Silicon + Intel)  |  Windows 10/11  |  Linux
    Python 3.12+ required

    Usage:
        python install.py
"""

import os, sys, subprocess, shutil, platform, time, textwrap
from pathlib import Path
import base64, ast

SCRIPT_DIR = Path(__file__).resolve().parent

_steps_total = 0
_steps_done  = 0

# ──────────────────────────────────────────────────────────────────
# CONSTANTS
# ──────────────────────────────────────────────────────────────────
VERSION      = "1.0.0"
PYTHON_MIN   = (3, 12)
INSTALL_ROOT = Path.home() / "Anduril"
DASH_DIR     = INSTALL_ROOT / "dashboard"
VENV_DIR     = INSTALL_ROOT / "venv"
ENV_FILE     = INSTALL_ROOT / ".env.trading"
IS_WIN       = platform.system() == "Windows"
IS_MAC       = platform.system() == "Darwin"
IS_LINUX     = platform.system() == "Linux"
IS_ARM       = platform.machine() in ("arm64", "aarch64")

PYTHON_EXE   = str(VENV_DIR / ("Scripts" if IS_WIN else "bin") / ("python.exe" if IS_WIN else "python"))
PIP_EXE      = str(VENV_DIR / ("Scripts" if IS_WIN else "bin") / ("pip.exe"    if IS_WIN else "pip"))
LAUNCH_EXE   = str(INSTALL_ROOT / ("launch.bat" if IS_WIN else "launch.sh"))

PACKAGES = [
    "numpy", "pandas", "scipy",
    "plotly>=5.18", "dash>=2.14", "dash-bootstrap-components",
    "yfinance>=0.2", "finnhub-python", "ta",
    "python-dotenv", "requests", "websocket-client",
    "vaderSentiment", "jupyterlab", "ipywidgets",
    "backtesting", "rich", "tqdm",
]

# ──────────────────────────────────────────────────────────────────
# COLORS  (ANSI -- works on Mac/Linux; Windows 10+ with VT enabled)
# ──────────────────────────────────────────────────────────────────
if IS_WIN:
    os.system("color")   # enable VT100 on Windows terminal

R  = "\033[0;31m";  G  = "\033[0;32m";  Y  = "\033[38;5;208m"
C  = "\033[38;5;99m";  W  = "\033[1;37m";  M  = "\033[38;5;208m"
DIM= "\033[2m";     NC = "\033[0m"

def clr(color, text): return f"{color}{text}{NC}"
def banner_line(text="", width=65):
    pad = (width - len(text)) // 2
    return f"  {clr(C, '║')}  {' ' * pad}{clr(W, text)}{clr(C, '  ║')}"

# ──────────────────────────────────────────────────────────────────
# BANNER
# ──────────────────────────────────────────────────────────────────
def print_banner():
    sword = [
        "                    /|",
        "                   / |",
        "                  /  |",
        "      ___________/   |",
        "     |  ANDURIL  >=======)",
        "     |___________|  |",
        "                  |  |",
        "                  |  |",
        "                  +--+",
    ]
    print()
    print(clr(C, "  " + "═" * 63))
    print(clr(C, "  ║") + " " * 63 + clr(C, "║"))
    for line in sword:
        pad_r = 63 - len(line) - 2
        print(clr(C, "  ║") + clr(Y, "  " + line) + " " * max(0, pad_r) + clr(C, "║"))
    print(clr(C, "  ║") + " " * 63 + clr(C, "║"))
    print(clr(C, "  ║") + clr(W, "      A N D U R I L   T R A D I N G   S U I T E      ") + "   " + clr(C, "║"))
    print(clr(C, "  ║") + clr(DIM, "             Flame of the West  --  Reforged             ") + clr(C, "║"))
    print(clr(C, "  ║") + " " * 63 + clr(C, "║"))
    plat = f"{'macOS' if IS_MAC else 'Windows'} {'arm64' if IS_ARM else platform.machine()}  |  Python {sys.version.split()[0]}"
    pad = (61 - len(plat)) // 2
    print(clr(C, "  ║") + " " * (pad+2) + clr(DIM, plat) + " " * (61 - pad - len(plat)) + clr(C, "║"))
    print(clr(C, "  ║") + " " * 63 + clr(C, "║"))
    print(clr(C, "  " + "═" * 63))
    print()

# ──────────────────────────────────────────────────────────────────
# LOGGING
# ──────────────────────────────────────────────────────────────────
_steps_total = 0
_steps_done  = 0

def section(title):
    print()
    print(clr(C, "  ┌─ ") + clr(W, title.upper()) + clr(C, " " + "─" * max(0, 56 - len(title)) + "┐"))

def step(msg):
    global _steps_done
    _steps_done += 1
    bar = clr(DIM, f"[{_steps_done:>2}/{_steps_total}]")
    print(f"  {bar}  {clr(Y, '▸')}  {msg}")

def ok(msg):
    print(f"  {clr(G, '  ✓')}  {msg}")

def warn(msg):
    print(f"  {clr(Y, '  ⚠')}  {msg}")

def fail(msg):
    print(f"  {clr(R, '  ✗')}  {msg}")
    sys.exit(1)

def progress_bar(label, n, total, width=30):
    filled = int(width * n / total)
    bar = clr(G, "█" * filled) + clr(DIM, "░" * (width - filled))
    pct = f"{n/total*100:.0f}%"
    print(f"  {clr(DIM, label):<30}  [{bar}]  {clr(W, pct)}", end="\r")
    if n == total:
        print()

# ──────────────────────────────────────────────────────────────────
# HELPERS
# ──────────────────────────────────────────────────────────────────
def run(cmd, check=True, capture=False, **kw):
    result = subprocess.run(
        cmd, shell=isinstance(cmd, str),
        capture_output=capture, text=True, **kw)
    if check and result.returncode != 0:
        if capture:
            fail(f"Command failed: {cmd}\n{result.stderr or result.stdout}")
        else:
            fail(f"Command failed: {cmd}")
    return result

LOGO_PNG_NAME = "anduril_trading.png"
LOGO_ICON_NAME = "anduril_trading_icon.png"

def _logo_png_sources():
    found = []
    for name in (LOGO_PNG_NAME, LOGO_ICON_NAME):
        p = SCRIPT_DIR / name
        if p.exists():
            found.append(p)
    return found

def _logo_icon_source():
    for name in (LOGO_ICON_NAME, LOGO_PNG_NAME):
        p = SCRIPT_DIR / name
        if p.exists():
            return p
    return None

def _set_mac_file_icon(target, image_path):
    if not IS_MAC or not target.exists() or not image_path.exists():
        return False
    try:
        target_s = str(target.resolve())
        image_s = str(image_path.resolve())
        script = (
            'use framework "AppKit"\n'
            f'set theImage to current application\'s NSImage\'s alloc()\'s initWithContentsOfFile:"{image_s}"\n'
            'if theImage is missing value then error "Could not load image"\n'
            f'current application\'s NSWorkspace\'s sharedWorkspace()\'s setIcon:theImage forFile:"{target_s}" options:0'
        )
        result = run(["osascript", "-e", script], check=False, capture=True)
        return result.returncode == 0
    except Exception:
        return False

def check_disk_space(min_gb=3):
    usage = shutil.disk_usage(Path.home())
    free_gb = usage.free / 1e9
    if free_gb < min_gb:
        fail(f"Need at least {min_gb}GB free. Only {free_gb:.1f}GB available.")
    return free_gb

def internet_check():
    import urllib.request
    try:
        urllib.request.urlopen("https://pypi.org", timeout=5)
        return True
    except:
        return False

def check_python_version():
    v = sys.version_info
    if (v.major, v.minor) < PYTHON_MIN:
        fail(f"Python {PYTHON_MIN[0]}.{PYTHON_MIN[1]}+ required. "
             f"You have {v.major}.{v.minor}.{v.micro}\n"
             f"  Download from: https://www.python.org/downloads/")

# ──────────────────────────────────────────────────────────────────
# PRE-FLIGHT
# ──────────────────────────────────────────────────────────────────
def preflight():
    section("Pre-Flight Check")
    global _steps_total
    _steps_total = 8

    step("Python version"); check_python_version()
    ok(f"Python {sys.version.split()[0]}")

    step("Platform")
    plat = f"{'macOS' if IS_MAC else 'Windows'} {platform.release()} ({'arm64' if IS_ARM else platform.machine()})"
    ok(plat)

    step("Disk space")
    free = check_disk_space(3)
    ok(f"{free:.1f} GB free")

    step("Internet connection")
    if not internet_check():
        fail("No internet. Connect and retry.")
    ok("Connected")

    step("Git")
    if shutil.which("git"):
        r = run("git --version", capture=True); ok(r.stdout.strip())
    else:
        warn("Git not found -- not required but recommended")

    step("Install directory")
    INSTALL_ROOT.mkdir(parents=True, exist_ok=True)
    DASH_DIR.mkdir(parents=True, exist_ok=True)
    (INSTALL_ROOT / "notebooks").mkdir(exist_ok=True)
    ok(str(INSTALL_ROOT))

    print()
    confirm = input(f"  {clr(W, 'Install Anduril Trading Suite?')}  {clr(DIM, '[y/N]')}  ").strip().lower()
    if confirm not in ("y", "yes"):
        print(f"  {clr(DIM, 'Cancelled.')}"); sys.exit(0)

# ──────────────────────────────────────────────────────────────────
# VIRTUAL ENVIRONMENT
# ──────────────────────────────────────────────────────────────────
def setup_venv():
    section("Virtual Environment")
    global _steps_done, _steps_total
    _steps_total += 3

    step("Creating virtual environment")
    if VENV_DIR.exists():
        ok("Already exists")
    else:
        run([sys.executable, "-m", "venv", str(VENV_DIR)])
        ok(f"Created at {VENV_DIR}")

    step("Upgrading pip")
    run([PYTHON_EXE, "-m", "pip", "install", "--upgrade", "pip", "setuptools", "wheel", "-q"])
    ok("pip up to date")

    # Fix pip cache permissions on Mac if needed
    if IS_MAC:
        cache = Path.home() / "Library" / "Caches" / "pip"
        if cache.exists():
            step("Fixing pip cache permissions")
            run(["chown", "-R", os.environ.get("USER", ""), str(cache)], check=False)
            ok("Cache permissions fixed")
        else:
            _steps_done += 1

# ──────────────────────────────────────────────────────────────────
# PACKAGES
# ──────────────────────────────────────────────────────────────────
def install_packages():
    section("Installing Packages")
    global _steps_total
    _steps_total += len(PACKAGES)

    for i, pkg in enumerate(PACKAGES, 1):
        step(f"{pkg}")
        result = run(
            [PYTHON_EXE, "-m", "pip", "install", pkg, "-q"],
            check=False, capture=True)
        if result.returncode != 0:
            warn(f"  {pkg} failed -- {result.stderr.strip()[:80]}")
        else:
            ok(pkg)
        progress_bar("Installing packages", i, len(PACKAGES))

# ──────────────────────────────────────────────────────────────────
# ENV FILE
# ──────────────────────────────────────────────────────────────────
def write_env():
    section("API Keys Configuration")
    global _steps_done, _steps_total
    _steps_total += 1; step("Writing .env.trading")

    if ENV_FILE.exists():
        ok(".env.trading already exists -- skipping")
        return

    ENV_FILE.write_text(textwrap.dedent("""
        # Anduril Trading Suite -- API Keys
        # Fill in the keys below. Never share this file.
        # ─────────────────────────────────────────────────────────

        # FINNHUB -- free at https://finnhub.io  (60 calls/min)
        # Used for: live quotes, Level 2, news, earnings, analyst data
        FINNHUB_API_KEY=YOUR_KEY_HERE

        # NEWSDATA.IO -- free at https://newsdata.io (200 credits/day = 2000 articles)
        # Used for: live news feed, geopolitical, macro, markets (12hr delay on free tier)
        NEWSDATA_API_KEY=YOUR_KEY_HERE

        # TWELVE DATA -- free at https://twelvedata.com (800 calls/day)
        # Used for: price history fallback, forex pairs, earnings calendar, technical indicators
        TWELVE_DATA_API_KEY=YOUR_KEY_HERE

        # ALWAYS FREE (no key needed)
        # Yahoo Finance : yfinance -- price history, charts, financials
    """).lstrip())
    ok(f"Created: {ENV_FILE}")
    warn("Open .env.trading and add your FINNHUB_API_KEY before launching")

# ──────────────────────────────────────────────────────────────────
# APP.PY
# ──────────────────────────────────────────────────────────────────
GUIDE_B64 = ""

OPTIONS_GUIDE_B64 = ""

LOGO_B64 = ""

LOGO_PNG_B64 = ""






APP_CODE_B64 = ""

def write_app():
    section("Writing Application Files")
    global _steps_total
    _steps_total += 5

    step("Decoding dashboard app")
    app_code = base64.b64decode(APP_CODE_B64).decode("utf-8")
    ast.parse(app_code)
    ok(f"app.py — {len(app_code.splitlines())} lines")

    step("Writing dashboard/app.py")
    app_path = DASH_DIR / "app.py"
    app_path.write_text(app_code, encoding="utf-8")
    ok(str(app_path))

    step("Writing guide.html")
    guide_dest = INSTALL_ROOT / "guide.html"
    local_guide = SCRIPT_DIR / "guide.html"
    if local_guide.exists():
        shutil.copy2(local_guide, guide_dest)
        ok(f"Copied {local_guide.name}")
    else:
        guide_dest.write_bytes(base64.b64decode(GUIDE_B64))
        ok("Written from embedded guide")

    step("Writing options_guide.html")
    og_dest = INSTALL_ROOT / "options_guide.html"
    local_og = SCRIPT_DIR / "options_guide.html"
    if local_og.exists():
        shutil.copy2(local_og, og_dest)
        ok(f"Copied {local_og.name}")
    else:
        og_dest.write_bytes(base64.b64decode(OPTIONS_GUIDE_B64))
        ok("Written from embedded options guide")

    step("Writing logo assets")
    (INSTALL_ROOT / "anduril_logo.svg").write_bytes(base64.b64decode(LOGO_B64))
    local_pngs = _logo_png_sources()
    if local_pngs:
        for src in local_pngs:
            shutil.copy2(src, INSTALL_ROOT / src.name)
        ok(f"Logo PNGs → {', '.join(p.name for p in local_pngs)}")
    else:
        (INSTALL_ROOT / LOGO_PNG_NAME).write_bytes(base64.b64decode(LOGO_PNG_B64))
        ok(f"Logo written → {LOGO_PNG_NAME}")

def write_launcher():
    section("Creating Launcher")
    global _steps_total
    _steps_total += 2

    step("Writing launch script")
    if IS_WIN:
        launch = INSTALL_ROOT / "launch.bat"
        launch.write_text(textwrap.dedent(f"""            @echo off
            call "{VENV_DIR / 'Scripts' / 'activate.bat'}"
            echo.
            echo   Anduril Trading Suite starting...
            echo   Opening browser at http://127.0.0.1:8050
            echo   Press Ctrl+C to stop.
            echo.
            timeout /t 2 /nobreak >nul
            start http://127.0.0.1:8050
            "{PYTHON_EXE}" "{DASH_DIR / 'app.py'}"
        """))
        ok(str(launch))
    else:
        launch = INSTALL_ROOT / "launch.sh"
        launch.write_text(textwrap.dedent(f"""            #!/usr/bin/env bash
            source "{VENV_DIR / 'bin' / 'activate'}"
            echo ""
            echo "  Anduril Trading Suite starting..."
            echo "  Opening browser at http://127.0.0.1:8050"
            echo "  Press Ctrl+C to stop.  |  Open guide: {INSTALL_ROOT / 'guide.html'}"
            echo ""
            sleep 1
            open "http://127.0.0.1:8050" 2>/dev/null || xdg-open "http://127.0.0.1:8050" 2>/dev/null || true
            python "{DASH_DIR / 'app.py'}"
        """))
        launch.chmod(0o755)
        ok(str(launch))

    step("Creating desktop shortcut")
    try:
        if IS_WIN:
            desktop = Path.home() / "Desktop" / "Anduril Trading.bat"
            shutil.copy2(launch, desktop)
        elif IS_MAC:
            cmd = INSTALL_ROOT / "Anduril Trading.command"
            cmd.write_text(textwrap.dedent(f"""\
                #!/usr/bin/env bash
                source "{VENV_DIR / 'bin' / 'activate'}"
                open "http://127.0.0.1:8050"
                python "{DASH_DIR / 'app.py'}"
            """))
            cmd.chmod(0o755)
            desktop = Path.home() / "Desktop" / "Anduril Trading.command"
            if desktop.exists():
                desktop.unlink()
            shutil.copy2(cmd, desktop)
            icon_png = INSTALL_ROOT / LOGO_ICON_NAME
            if not icon_png.exists():
                icon_png = INSTALL_ROOT / LOGO_PNG_NAME
            if icon_png.exists():
                if _set_mac_file_icon(cmd, icon_png):
                    ok("Desktop shortcut icon applied")
                _set_mac_file_icon(desktop, icon_png)
        else:
            desktop = Path.home() / "Desktop" / "Anduril Trading.desktop"
            desktop.write_text(textwrap.dedent(f"""\
                [Desktop Entry]
                Name=Anduril Trading
                Comment=Personal Trading Dashboard
                Exec=bash {INSTALL_ROOT / 'launch.sh'}
                Icon={INSTALL_ROOT / LOGO_PNG_NAME}
                Terminal=true
                Type=Application
                Categories=Finance;
            """))
            desktop.chmod(0o755)
        ok(f"Desktop shortcut created")
    except Exception as e:
        warn(f"Desktop shortcut skipped: {e}")

